-- ============================================================
-- Functions
CREATE OR REPLACE FUNCTION public.accept_friend_request(p_friendship_id uuid, p_requester_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_accepter_id uuid;
  v_requester_name text;
  v_accepter_name text;
BEGIN
  v_accepter_id := auth.uid();
  IF v_accepter_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Verify this is a pending request sent TO the current user
  IF NOT EXISTS (
    SELECT 1 FROM friendships
    WHERE id = p_friendship_id
      AND friend_user_id = v_accepter_id
      AND status = 'pending'
  ) THEN
    RAISE EXCEPTION 'Friend request not found or not pending';
  END IF;

  -- Update the sender's original record to connected
  UPDATE friendships
  SET status = 'connected', updated_at = now()
  WHERE id = p_friendship_id;

  -- Get names for the reciprocal record
  SELECT display_name INTO v_requester_name FROM profiles WHERE user_id = p_requester_user_id;
  SELECT display_name INTO v_accepter_name FROM profiles WHERE user_id = v_accepter_id;

  -- Create reciprocal friendship for the accepter (if not exists)
  INSERT INTO friendships (user_id, friend_user_id, friend_name, status)
  VALUES (v_accepter_id, p_requester_user_id, COALESCE(v_requester_name, 'Friend'), 'connected')
  ON CONFLICT DO NOTHING;

  -- Also update sender's record friend_name in case it was stale
  UPDATE friendships
  SET friend_name = COALESCE(v_accepter_name, friend_name), updated_at = now()
  WHERE user_id = p_requester_user_id AND friend_user_id = v_accepter_id AND status = 'pending';

  -- Mark any remaining pending record from sender -> accepter as connected too
  UPDATE friendships
  SET status = 'connected', updated_at = now()
  WHERE user_id = p_requester_user_id AND friend_user_id = v_accepter_id AND status = 'pending';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.accept_plan_invite(p_token text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invite RECORD;
  v_user_id UUID;
  v_user_name TEXT;
  v_friend_label TEXT;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  SELECT pi.*, p.user_id AS plan_owner_id
  INTO v_invite
  FROM plan_invites pi
  JOIN plans p ON p.id = pi.plan_id
  WHERE pi.invite_token = p_token AND pi.status = 'pending';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invite not found or already used';
  END IF;

  IF v_invite.plan_owner_id = v_user_id THEN
    RAISE EXCEPTION 'Cannot accept your own plan invite';
  END IF;

  IF EXISTS (SELECT 1 FROM plan_participants WHERE plan_id = v_invite.plan_id AND friend_id = v_user_id) THEN
    -- Already in plan; still mark invite accepted to clear placeholder UI
    UPDATE plan_invites
    SET status = 'accepted', accepted_at = now(), accepted_by = v_user_id
    WHERE id = v_invite.id;
    RETURN v_invite.plan_id;
  END IF;

  INSERT INTO plan_participants (plan_id, friend_id, status, role, responded_at)
  VALUES (v_invite.plan_id, v_user_id, 'accepted', 'participant', now());

  UPDATE plan_invites
  SET status = 'accepted', accepted_at = now(), accepted_by = v_user_id
  WHERE id = v_invite.id;

  SELECT display_name INTO v_user_name FROM profiles WHERE user_id = v_user_id;

  -- Inviter -> accepter friendship: prefer the placeholder name they originally typed,
  -- so the placeholder seamlessly becomes a real friend with the expected label.
  v_friend_label := COALESCE(NULLIF(trim(v_invite.placeholder_name), ''), v_user_name, 'Friend');

  INSERT INTO friendships (user_id, friend_user_id, friend_name, status)
  VALUES (v_invite.invited_by, v_user_id, v_friend_label, 'connected')
  ON CONFLICT DO NOTHING;

  INSERT INTO friendships (user_id, friend_user_id, friend_name, status)
  SELECT v_user_id, v_invite.invited_by, COALESCE(pr.display_name, 'Friend'), 'connected'
  FROM profiles pr WHERE pr.user_id = v_invite.invited_by
  ON CONFLICT DO NOTHING;

  RETURN v_invite.plan_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.accept_trip_invite(p_token text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id UUID;
  v_invite RECORD;
  v_proposal RECORD;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  SELECT * INTO v_invite
  FROM trip_proposal_invites
  WHERE invite_token = p_token;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invite not found';
  END IF;

  SELECT * INTO v_proposal
  FROM trip_proposals
  WHERE id = v_invite.proposal_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Proposal not found';
  END IF;

  -- Add to proposal participants if not already there
  INSERT INTO trip_proposal_participants (proposal_id, user_id, status)
  VALUES (v_invite.proposal_id, v_user_id, 'invited')
  ON CONFLICT DO NOTHING;

  -- If a trip already exists (finalized), add to trip_participants
  IF v_invite.trip_id IS NOT NULL THEN
    INSERT INTO trip_participants (trip_id, friend_user_id)
    VALUES (v_invite.trip_id, v_user_id)
    ON CONFLICT DO NOTHING;
  END IF;

  -- Mark invite accepted (only if still pending)
  IF v_invite.status = 'pending' THEN
    UPDATE trip_proposal_invites
    SET status = 'accepted',
        accepted_by = v_user_id,
        accepted_at = now()
    WHERE id = v_invite.id;
  END IF;

  RETURN json_build_object(
    'proposal_id', v_invite.proposal_id,
    'trip_id', v_invite.trip_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.approve_participant_request(p_request_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_request RECORD;
  v_caller_id UUID;
BEGIN
  v_caller_id := auth.uid();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Get the request and verify caller is the plan organizer
  SELECT pr.*, p.user_id AS plan_owner_id
  INTO v_request
  FROM plan_participant_requests pr
  JOIN plans p ON p.id = pr.plan_id
  WHERE pr.id = p_request_id AND pr.status = 'pending';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Request not found or already resolved';
  END IF;

  IF v_request.plan_owner_id != v_caller_id THEN
    RAISE EXCEPTION 'Only the plan organizer can approve requests';
  END IF;

  -- Check if already a participant
  IF EXISTS (SELECT 1 FROM plan_participants WHERE plan_id = v_request.plan_id AND friend_id = v_request.friend_user_id) THEN
    RAISE EXCEPTION 'User is already a participant';
  END IF;

  -- Add as participant
  INSERT INTO plan_participants (plan_id, friend_id, status, role)
  VALUES (v_request.plan_id, v_request.friend_user_id, 'accepted', 'participant');

  -- Mark request as approved
  UPDATE plan_participant_requests
  SET status = 'approved', resolved_at = now()
  WHERE id = p_request_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_create_trip_from_availability()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_home_address TEXT;
  v_run_start DATE;
  v_run_end DATE;
  v_current_location TEXT;
  v_norm_trip TEXT;
  v_norm_home TEXT;
  v_trip_city TEXT;
  v_home_city TEXT;
  v_old_run_start DATE;
  v_old_run_end DATE;
  v_trip RECORD;
  v_tbc_trip RECORD;
BEGIN
  -- FAST PATH: if the client tagged this row with a trip_id, the app owns the trip lifecycle.
  IF NEW.trip_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Get user's home address (only used for legacy path)
  SELECT home_address INTO v_home_address FROM public.profiles WHERE user_id = NEW.user_id;

  -- LEGACY CLEANUP PATH: row set back to 'home' or trip_location cleared, with no trip_id
  IF NEW.location_status = 'home' OR NEW.trip_location IS NULL THEN
    FOR v_trip IN
      SELECT id, location, start_date, end_date
      FROM public.trips
      WHERE user_id = NEW.user_id
        AND start_date <= NEW.date
        AND end_date   >= NEW.date
    LOOP
      -- Skip TBC trips (location IS NULL). They are user-owned placeholders that
      -- should not be auto-shrunk/deleted by availability cleanup heuristics.
      IF v_trip.location IS NULL THEN
        CONTINUE;
      END IF;

      v_old_run_start := NULL;
      v_old_run_end   := NULL;

      SELECT MIN(date) INTO v_old_run_start
      FROM public.availability
      WHERE user_id = NEW.user_id
        AND date >= v_trip.start_date
        AND date <= v_trip.end_date
        AND location_status = 'away'
        AND trip_location IS NOT NULL
        AND public.normalize_trip_city(trip_location) = public.normalize_trip_city(v_trip.location);

      IF v_old_run_start IS NOT NULL THEN
        v_old_run_end := v_old_run_start;
        LOOP
          EXIT WHEN NOT EXISTS (
            SELECT 1 FROM public.availability
            WHERE user_id = NEW.user_id
              AND date = v_old_run_end + 1
              AND location_status = 'away'
              AND trip_location IS NOT NULL
              AND public.normalize_trip_city(trip_location) = public.normalize_trip_city(v_trip.location)
          );
          v_old_run_end := v_old_run_end + 1;
        END LOOP;
      END IF;

      IF v_old_run_start IS NULL OR (v_old_run_end - v_old_run_start) < 1 THEN
        DELETE FROM public.trips WHERE id = v_trip.id;
      ELSIF v_old_run_start != v_trip.start_date OR v_old_run_end != v_trip.end_date THEN
        UPDATE public.trips
        SET start_date = v_old_run_start,
            end_date   = v_old_run_end,
            updated_at = now()
        WHERE id = v_trip.id;
      END IF;
    END LOOP;

    RETURN NEW;
  END IF;

  -- AT THIS POINT: NEW.location_status = 'away' AND NEW.trip_location IS NOT NULL

  -- TBC MERGE PATH: if a real destination arrives on a date overlapping an
  -- existing "TBC" (location IS NULL) trip for the same user, fill it in
  -- rather than creating a duplicate trip.
  SELECT id, start_date, end_date
    INTO v_tbc_trip
  FROM public.trips
  WHERE user_id = NEW.user_id
    AND location IS NULL
    AND start_date <= NEW.date
    AND end_date   >= NEW.date
  ORDER BY created_at ASC
  LIMIT 1;

  IF v_tbc_trip.id IS NOT NULL THEN
    UPDATE public.trips
    SET location   = NEW.trip_location,
        updated_at = now()
    WHERE id = v_tbc_trip.id;

    -- Link this availability row (and any other away-without-trip-id rows in
    -- the trip's date range) to the now-resolved trip.
    UPDATE public.availability
    SET trip_id = v_tbc_trip.id
    WHERE user_id = NEW.user_id
      AND date BETWEEN v_tbc_trip.start_date AND v_tbc_trip.end_date
      AND location_status = 'away'
      AND trip_id IS NULL;

    RETURN NEW;
  END IF;

  -- LEGACY AUTO-CREATE PATH (unchanged): only when the row's trip_location
  -- is meaningfully different from the user's home, build/extend a trip.
  v_norm_trip := public.normalize_trip_city(NEW.trip_location);
  v_norm_home := public.normalize_trip_city(v_home_address);
  IF v_norm_trip IS NOT NULL AND v_norm_home IS NOT NULL AND v_norm_trip = v_norm_home THEN
    RETURN NEW;
  END IF;

  v_current_location := NEW.trip_location;

  -- Find the contiguous away-run for this same city around NEW.date
  SELECT MIN(date), MAX(date) INTO v_run_start, v_run_end
  FROM (
    SELECT date
    FROM public.availability
    WHERE user_id = NEW.user_id
      AND location_status = 'away'
      AND trip_location IS NOT NULL
      AND public.normalize_trip_city(trip_location) = v_norm_trip
      AND date BETWEEN (NEW.date - INTERVAL '60 days') AND (NEW.date + INTERVAL '60 days')
  ) sub;

  IF v_run_start IS NULL THEN
    v_run_start := NEW.date;
    v_run_end   := NEW.date;
  END IF;

  -- Look for an existing trip that already covers this run for this city
  SELECT id, start_date, end_date INTO v_trip
  FROM public.trips
  WHERE user_id = NEW.user_id
    AND location IS NOT NULL
    AND public.normalize_trip_city(location) = v_norm_trip
    AND start_date <= v_run_end
    AND end_date   >= v_run_start
  ORDER BY start_date ASC
  LIMIT 1;

  IF v_trip.id IS NOT NULL THEN
    IF v_trip.start_date != v_run_start OR v_trip.end_date != v_run_end THEN
      UPDATE public.trips
      SET start_date = LEAST(v_trip.start_date, v_run_start),
          end_date   = GREATEST(v_trip.end_date, v_run_end),
          updated_at = now()
      WHERE id = v_trip.id;
    END IF;
  ELSE
    -- Need at least 2 consecutive days to auto-materialise a trip
    IF (v_run_end - v_run_start) >= 1 THEN
      INSERT INTO public.trips (user_id, location, start_date, end_date, available_slots, priority_friend_ids)
      VALUES (
        NEW.user_id,
        v_current_location,
        v_run_start,
        v_run_end,
        ARRAY['early-morning','late-morning','early-afternoon','late-afternoon','evening','late-night']::text[],
        ARRAY[]::uuid[]
      );
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.backfill_availability_for_all_users(_days_ahead integer DEFAULT 183)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _user RECORD;
  _total int := 0;
BEGIN
  FOR _user IN SELECT user_id FROM profiles LOOP
    _total := _total + COALESCE(public.backfill_availability_for_user(_user.user_id, _days_ahead), 0);
  END LOOP;
  RETURN _total;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.backfill_availability_for_user(_user_id uuid, _days_ahead integer DEFAULT 183)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _profile RECORD;
  _date date;
  _start date := CURRENT_DATE;
  _end date := CURRENT_DATE + _days_ahead;
  _dow_name text;
  _is_workday boolean;
  _default_free boolean;
  _early_morning boolean;
  _late_morning boolean;
  _early_afternoon boolean;
  _late_afternoon boolean;
  _evening boolean;
  _late_night boolean;
  _ws numeric;
  _we numeric;
  _inserted int := 0;
BEGIN
  SELECT
    COALESCE(default_work_days, ARRAY['monday','tuesday','wednesday','thursday','friday']) AS work_days,
    COALESCE(default_work_start_hour, 9) AS work_start,
    COALESCE(default_work_end_hour, 17) AS work_end,
    COALESCE(default_availability_status, 'free') AS default_status
  INTO _profile
  FROM profiles
  WHERE user_id = _user_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  _default_free := _profile.default_status <> 'unavailable';
  _ws := _profile.work_start;
  _we := _profile.work_end;

  _date := _start;
  WHILE _date <= _end LOOP
    _dow_name := lower(to_char(_date, 'FMday'));
    _is_workday := _dow_name = ANY(_profile.work_days);

    -- Slot ranges: EM 6-9, LM 9-12, EA 12-15, LA 15-18, EV 18-22, LN 22-26
    _early_morning   := _default_free;
    _late_morning    := _default_free;
    _early_afternoon := _default_free;
    _late_afternoon  := _default_free;
    _evening         := _default_free;
    _late_night      := _default_free;

    IF _is_workday THEN
      IF 6  < _we AND 9  > _ws THEN _early_morning   := false; END IF;
      IF 9  < _we AND 12 > _ws THEN _late_morning    := false; END IF;
      IF 12 < _we AND 15 > _ws THEN _early_afternoon := false; END IF;
      IF 15 < _we AND 18 > _ws THEN _late_afternoon  := false; END IF;
      IF 18 < _we AND 22 > _ws THEN _evening         := false; END IF;
      IF 22 < _we AND 26 > _ws THEN _late_night      := false; END IF;
    END IF;

    INSERT INTO availability (
      user_id, date,
      early_morning, late_morning, early_afternoon, late_afternoon, evening, late_night,
      location_status
    )
    VALUES (
      _user_id, _date,
      _early_morning, _late_morning, _early_afternoon, _late_afternoon, _evening, _late_night,
      'home'
    )
    ON CONFLICT (user_id, date) DO NOTHING;

    IF FOUND THEN
      _inserted := _inserted + 1;
    END IF;

    _date := _date + 1;
  END LOOP;

  RETURN _inserted;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_and_apply_plan_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_request RECORD;
  v_all_accepted BOOLEAN;
BEGIN
  -- Only trigger when response changes to 'accepted'
  IF NEW.response = 'accepted' THEN
    -- Check if all responses for this request are now 'accepted'
    SELECT NOT EXISTS (
      SELECT 1 FROM plan_change_responses
      WHERE change_request_id = NEW.change_request_id
      AND response != 'accepted'
    ) INTO v_all_accepted;

    IF v_all_accepted THEN
      -- Get the change request details
      SELECT * INTO v_request FROM plan_change_requests WHERE id = NEW.change_request_id;

      -- Apply the changes to the plan
      UPDATE plans SET
        date = COALESCE(v_request.proposed_date, date),
        time_slot = COALESCE(v_request.proposed_time_slot, time_slot),
        duration = COALESCE(v_request.proposed_duration, duration),
        updated_at = now()
      WHERE id = v_request.plan_id;

      -- Mark the change request as accepted
      UPDATE plan_change_requests
      SET status = 'accepted', resolved_at = now()
      WHERE id = NEW.change_request_id;
    END IF;
  ELSIF NEW.response = 'declined' THEN
    -- If any participant declines, mark the whole request as declined
    UPDATE plan_change_requests
    SET status = 'declined', resolved_at = now()
    WHERE id = NEW.change_request_id;
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_phone_available(p_phone text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE public.normalize_phone(phone_number) = public.normalize_phone(p_phone)
      AND public.normalize_phone(p_phone) IS NOT NULL
      AND user_id != COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid)
  );
$function$
;

CREATE OR REPLACE FUNCTION public.check_username_available(p_username text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE lower(display_name) = lower(p_username)
      AND user_id != auth.uid()
  );
$function$
;

CREATE OR REPLACE FUNCTION public.check_vibe_recipient(p_vibe_send_id uuid)
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM vibe_send_recipients
    WHERE vibe_send_id = p_vibe_send_id
    AND recipient_id = auth.uid()
  );
$function$
;

CREATE OR REPLACE FUNCTION public.check_vibe_sender(p_vibe_send_id uuid)
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM vibe_sends
    WHERE id = p_vibe_send_id
    AND sender_id = auth.uid()
  );
$function$
;

CREATE OR REPLACE FUNCTION public.convert_open_invite_to_plan()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invite public.open_invites%ROWTYPE;
  v_plan_id UUID;
BEGIN
  IF NEW.response <> 'claimed' THEN
    RETURN NEW;
  END IF;

  SELECT * INTO v_invite FROM public.open_invites WHERE id = NEW.open_invite_id FOR UPDATE;

  -- Only convert the first claim
  IF v_invite.status <> 'open' THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.plans (
    user_id, title, activity, date, time_slot, start_time, end_time, duration,
    location, notes, status, feed_visibility
  ) VALUES (
    v_invite.user_id, v_invite.title, v_invite.activity, v_invite.date, v_invite.time_slot,
    v_invite.start_time, v_invite.end_time, v_invite.duration,
    v_invite.location, v_invite.notes, 'confirmed', 'friends'
  ) RETURNING id INTO v_plan_id;

  -- Add the claimer as an accepted participant
  INSERT INTO public.plan_participants (plan_id, friend_id, status, role, responded_at)
  VALUES (v_plan_id, NEW.user_id, 'accepted', 'participant', now());

  -- Mark invite as claimed
  UPDATE public.open_invites
  SET status = 'claimed', claimed_plan_id = v_plan_id, updated_at = now()
  WHERE id = NEW.open_invite_id;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_plans_on_hang_accepted()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_recipient_name TEXT;
  v_sender_name TEXT;
  v_time_slot TEXT;
  v_plan_title_for_recipient TEXT;
  v_plan_title_for_sender TEXT;
  v_recipient_plan_id UUID;
  v_sender_plan_id UUID;
  v_plan_date TIMESTAMP WITH TIME ZONE;
  v_recipient_tz TEXT;
  v_sender_tz TEXT;
BEGIN
  IF NEW.status = 'accepted' AND (OLD.status IS DISTINCT FROM 'accepted') THEN
    SELECT display_name INTO v_recipient_name FROM public.profiles WHERE user_id = NEW.user_id;
    SELECT timezone INTO v_recipient_tz FROM public.profiles WHERE user_id = NEW.user_id;
    
    v_time_slot := REPLACE(NEW.selected_slot, '_', '-');
    v_plan_title_for_recipient := 'Hang with ' || NEW.requester_name;
    v_plan_title_for_sender := 'Hang with ' || COALESCE(v_recipient_name, 'a friend');
    v_plan_date := (NEW.selected_day::text || 'T12:00:00+00:00')::timestamp with time zone;

    INSERT INTO public.plans (user_id, title, activity, date, time_slot, duration, notes, source, source_timezone)
    VALUES (
      NEW.user_id, v_plan_title_for_recipient, 'other-events', v_plan_date,
      v_time_slot, 60, COALESCE(NEW.message, ''), 'hang-request', v_recipient_tz
    )
    RETURNING id INTO v_recipient_plan_id;

    IF NEW.sender_id IS NOT NULL THEN
      SELECT timezone INTO v_sender_tz FROM public.profiles WHERE user_id = NEW.sender_id;
      
      INSERT INTO public.plans (user_id, title, activity, date, time_slot, duration, notes, source, source_timezone)
      VALUES (
        NEW.sender_id, v_plan_title_for_sender, 'other-events', v_plan_date,
        v_time_slot, 60, COALESCE(NEW.message, ''), 'hang-request', v_sender_tz
      )
      RETURNING id INTO v_sender_plan_id;

      INSERT INTO public.plan_participants (plan_id, friend_id, status)
      VALUES (v_recipient_plan_id, NEW.sender_id, 'accepted');

      INSERT INTO public.plan_participants (plan_id, friend_id, status)
      VALUES (v_sender_plan_id, NEW.user_id, 'accepted');
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.decrypt_calendar_token(encrypted_token bytea, p_key_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pgsodium'
AS $function$
BEGIN
  IF encrypted_token IS NULL THEN
    RETURN NULL;
  END IF;
  RETURN convert_from(
    pgsodium.crypto_aead_det_decrypt(
      encrypted_token,
      convert_to('calendar_token', 'utf8'),
      p_key_id,
      decode(replace(p_key_id::text, '-', ''), 'hex')
    ),
    'utf8'
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.encrypt_calendar_token(token text, p_key_id uuid)
 RETURNS bytea
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pgsodium'
AS $function$
BEGIN
  IF token IS NULL THEN
    RETURN NULL;
  END IF;

  -- The 16 bytes of the key UUID are used as a deterministic nonce.
  RETURN pgsodium.crypto_aead_det_encrypt(
    convert_to(token, 'utf8'),
    convert_to('calendar_token', 'utf8'),
    p_key_id,
    decode(replace(p_key_id::text, '-', ''), 'hex')
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_share_code(length integer DEFAULT 8)
 RETURNS text
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  chars TEXT := 'abcdefghjkmnpqrstuvwxyz23456789';
  result TEXT := '';
  i INTEGER;
BEGIN
  FOR i IN 1..length LOOP
    result := result || substr(chars, floor(random() * length(chars) + 1)::integer, 1);
  END LOOP;
  RETURN result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_availability_by_share_code(p_share_code text, p_start_date date, p_end_date date)
 RETURNS TABLE(date date, early_morning boolean, late_morning boolean, early_afternoon boolean, late_afternoon boolean, evening boolean, late_night boolean, location_status text, trip_location text, slot_location_early_morning text, slot_location_late_morning text, slot_location_early_afternoon text, slot_location_late_afternoon text, slot_location_evening text, slot_location_late_night text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT 
    a.date, a.early_morning, a.late_morning, a.early_afternoon,
    a.late_afternoon, a.evening, a.late_night,
    a.location_status, a.trip_location,
    a.slot_location_early_morning, a.slot_location_late_morning,
    a.slot_location_early_afternoon, a.slot_location_late_afternoon,
    a.slot_location_evening, a.slot_location_late_night
  FROM public.availability a
  JOIN public.profiles p ON p.user_id = a.user_id
  WHERE p.share_code = p_share_code
    AND p.show_availability = true
    AND a.date >= p_start_date
    AND a.date <= p_end_date
  ORDER BY a.date;
$function$
;

CREATE OR REPLACE FUNCTION public.get_calendar_tokens(p_user_id uuid, p_provider text)
 RETURNS TABLE(access_token text, refresh_token text, expires_at timestamp with time zone, grant_id text, ical_url text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    cc.access_token_plain  AS access_token,
    cc.refresh_token_plain AS refresh_token,
    cc.expires_at,
    cc.grant_id,
    cc.ical_url
  FROM public.calendar_connections cc
  WHERE cc.user_id = p_user_id AND cc.provider = p_provider;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_conflicting_trips(p_user_id uuid)
 RETURNS TABLE(trip_a_id uuid, trip_a_name text, trip_a_location text, trip_a_start date, trip_a_end date, trip_a_participant_ids uuid[], trip_b_id uuid, trip_b_name text, trip_b_location text, trip_b_start date, trip_b_end date, trip_b_participant_ids uuid[])
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH trip_people AS (
    SELECT t.id AS trip_id, ARRAY(
      SELECT DISTINCT uid FROM (
        SELECT unnest(t.priority_friend_ids) AS uid
        UNION
        SELECT tp.friend_user_id FROM public.trip_participants tp WHERE tp.trip_id = t.id
        UNION
        SELECT tpp.user_id
          FROM public.trip_proposal_participants tpp
         WHERE t.proposal_id IS NOT NULL
           AND tpp.proposal_id = t.proposal_id
           AND tpp.user_id <> t.user_id
      ) s
      WHERE uid IS NOT NULL
    ) AS people
    FROM public.trips t
    WHERE t.user_id = p_user_id
  )
  SELECT
    a.id, a.name, a.location, a.start_date, a.end_date,
    COALESCE(pa.people, '{}'::uuid[]),
    b.id, b.name, b.location, b.start_date, b.end_date,
    COALESCE(pb.people, '{}'::uuid[])
  FROM public.trips a
  JOIN public.trips b
    ON a.user_id = b.user_id
   AND a.id < b.id
   AND a.start_date <= b.end_date
   AND a.end_date   >= b.start_date
  LEFT JOIN trip_people pa ON pa.trip_id = a.id
  LEFT JOIN trip_people pb ON pb.trip_id = b.id
  WHERE a.user_id = p_user_id
    AND a.end_date >= CURRENT_DATE
    AND b.end_date >= CURRENT_DATE
  ORDER BY a.start_date;
$function$
;

CREATE OR REPLACE FUNCTION public.get_dashboard_data(p_user_id uuid, p_plan_cursor timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS json
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_avail_start date := (CURRENT_DATE - interval '7 days')::date;
  v_avail_end   date := (CURRENT_DATE + interval '35 days')::date;
  v_plan_start  date := (CURRENT_DATE - interval '14 days')::date;
  v_plan_limit  int := 200;
  v_result      json;
BEGIN
  WITH
  own_plans AS (
    SELECT p.id, p.user_id, p.title, p.activity, p.date, p.time_slot,
      p.duration, p.start_time, p.end_time, p.location, p.notes,
      p.status, p.feed_visibility, p.source, p.source_timezone,
      p.end_date, p.recurring_plan_id, p.created_at
    FROM public.plans p
    WHERE p.user_id = p_user_id
      AND p.date >= v_plan_start
      AND (p_plan_cursor IS NULL OR p.created_at < p_plan_cursor)
    ORDER BY p.date ASC
    LIMIT v_plan_limit
  ),
  participated_plan_ids AS (
    SELECT pp.plan_id FROM public.plan_participants pp WHERE pp.friend_id = p_user_id
  ),
  participated_plans AS (
    SELECT p.id, p.user_id, p.title, p.activity, p.date, p.time_slot,
      p.duration, p.start_time, p.end_time, p.location, p.notes,
      p.status, p.feed_visibility, p.source, p.source_timezone,
      p.end_date, p.recurring_plan_id, p.created_at
    FROM public.plans p INNER JOIN participated_plan_ids pid ON pid.plan_id = p.id
    WHERE p.user_id <> p_user_id
      AND p.date >= v_plan_start
      AND (p_plan_cursor IS NULL OR p.created_at < p_plan_cursor)
    ORDER BY p.date ASC
    LIMIT v_plan_limit
  ),
  all_plan_ids AS (
    SELECT id FROM own_plans UNION SELECT id FROM participated_plans
  ),
  plan_participants_data AS (
    SELECT pp.plan_id, pp.friend_id, pp.status, pp.role, pp.responded_at
    FROM public.plan_participants pp WHERE pp.plan_id IN (SELECT id FROM all_plan_ids)
  ),
  participant_user_ids AS (
    SELECT DISTINCT pp.friend_id AS uid FROM plan_participants_data pp
    UNION SELECT DISTINCT pp2.user_id AS uid FROM participated_plans pp2
  ),
  participant_profiles AS (
    SELECT pr.user_id, pr.display_name, pr.avatar_url
    FROM public.profile_cache pr
    WHERE pr.user_id IN (SELECT uid FROM participant_user_ids) AND pr.user_id <> p_user_id
  ),
  outgoing_friendships AS (
    SELECT f.id, f.user_id, f.friend_user_id, f.friend_name, f.friend_email,
      f.status, f.is_pod_member, f.created_at, f.updated_at
    FROM public.friendships f WHERE f.user_id = p_user_id
  ),
  outgoing_friend_user_ids AS (
    SELECT DISTINCT f.friend_user_id AS uid FROM outgoing_friendships f WHERE f.friend_user_id IS NOT NULL
  ),
  outgoing_friend_profiles AS (
    SELECT pr.user_id, pr.avatar_url FROM public.profile_cache pr
    WHERE pr.user_id IN (SELECT uid FROM outgoing_friend_user_ids)
  ),
  incoming_friendships AS (
    SELECT f.id, f.user_id, f.friend_user_id, f.friend_name, f.status, f.created_at, f.updated_at
    FROM public.friendships f WHERE f.friend_user_id = p_user_id
  ),
  incoming_friend_user_ids AS (
    SELECT DISTINCT f.user_id AS uid FROM incoming_friendships f
  ),
  incoming_friend_profiles AS (
    SELECT pr.user_id, pr.display_name, pr.avatar_url FROM public.profile_cache pr
    WHERE pr.user_id IN (SELECT uid FROM incoming_friend_user_ids)
  ),
  avail_data AS (
    SELECT a.date, a.early_morning, a.late_morning, a.early_afternoon,
      a.late_afternoon, a.evening, a.late_night,
      a.location_status, a.trip_location, a.vibe,
      a.slot_location_early_morning, a.slot_location_late_morning,
      a.slot_location_early_afternoon, a.slot_location_late_afternoon,
      a.slot_location_evening, a.slot_location_late_night
    FROM public.availability a
    WHERE a.user_id = p_user_id AND a.date >= v_avail_start AND a.date <= v_avail_end
  ),
  caller_profile AS (
    SELECT pr.current_vibe, pr.location_status, pr.custom_vibe_tags,
      pr.vibe_gif_url, pr.default_work_days, pr.default_work_start_hour,
      pr.default_work_end_hour, pr.default_availability_status,
      pr.default_vibes, pr.home_address, pr.timezone
    FROM public.profiles pr WHERE pr.user_id = p_user_id
  ),
  has_more AS (
    SELECT EXISTS (
      SELECT 1 FROM public.plans p
      WHERE (p.user_id = p_user_id OR p.id IN (SELECT plan_id FROM participated_plan_ids))
        AND p.date >= v_plan_start
        AND p.created_at < COALESCE(
          (SELECT MIN(created_at) FROM (SELECT created_at FROM own_plans UNION ALL SELECT created_at FROM participated_plans) sub),
          now()
        )
    ) AS val
  )
  SELECT json_build_object(
    'own_plans',               COALESCE((SELECT json_agg(row_to_json(op)) FROM own_plans op), '[]'::json),
    'participated_plans',      COALESCE((SELECT json_agg(row_to_json(pp)) FROM participated_plans pp), '[]'::json),
    'plan_participants',       COALESCE((SELECT json_agg(row_to_json(pd)) FROM plan_participants_data pd), '[]'::json),
    'participant_profiles',    COALESCE((SELECT json_agg(row_to_json(prof)) FROM participant_profiles prof), '[]'::json),
    'outgoing_friendships',    COALESCE((SELECT json_agg(row_to_json(of2)) FROM outgoing_friendships of2), '[]'::json),
    'outgoing_friend_profiles',COALESCE((SELECT json_agg(row_to_json(ofp)) FROM outgoing_friend_profiles ofp), '[]'::json),
    'incoming_friendships',    COALESCE((SELECT json_agg(row_to_json(inf)) FROM incoming_friendships inf), '[]'::json),
    'incoming_friend_profiles',COALESCE((SELECT json_agg(row_to_json(ifp)) FROM incoming_friend_profiles ifp), '[]'::json),
    'availability',            COALESCE((SELECT json_agg(row_to_json(av)) FROM avail_data av), '[]'::json),
    'profile',                 (SELECT row_to_json(cp) FROM caller_profile cp),
    'has_more_plans',          (SELECT val FROM has_more)
  ) INTO v_result;
  RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_dashboard_data(p_user_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_avail_start date := (CURRENT_DATE - interval '7 days')::date;
  v_avail_end   date := (CURRENT_DATE + interval '35 days')::date;
  v_plan_start  date := (CURRENT_DATE - interval '14 days')::date;
  v_result      json;
BEGIN
