CREATE OR REPLACE FUNCTION public.get_display_names_for_users(p_user_ids uuid[])
 RETURNS TABLE(user_id uuid, display_name text, avatar_url text, first_name text, last_name text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT p.user_id, p.display_name, p.avatar_url, p.first_name, p.last_name
  FROM profiles p
  WHERE p.user_id = ANY(p_user_ids);
$function$
;

CREATE OR REPLACE FUNCTION public.get_feed_plans(p_user_id uuid, p_limit integer DEFAULT 100)
 RETURNS json
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  result json;
BEGIN
  WITH connected_friends AS (
    SELECT friend_user_id
    FROM friendships
    WHERE user_id = p_user_id AND status = 'connected'
  ),
  participated_plan_ids AS (
    SELECT plan_id FROM plan_participants WHERE friend_id = p_user_id
  ),
  feed_plans AS (
    SELECT DISTINCT ON (p.id) p.*
    FROM plans p
    WHERE p.date < now()
      AND p.user_id <> p_user_id
      AND (
        (p.feed_visibility <> 'private' AND p.user_id IN (SELECT friend_user_id FROM connected_friends))
        OR p.id IN (SELECT plan_id FROM participated_plan_ids)
      )
    ORDER BY p.id, p.date DESC
    LIMIT p_limit
  ),
  ordered_plans AS (
    SELECT * FROM feed_plans ORDER BY date DESC
  ),
  all_user_ids AS (
    SELECT user_id AS uid FROM ordered_plans
    UNION
    SELECT pp.friend_id FROM plan_participants pp WHERE pp.plan_id IN (SELECT id FROM ordered_plans)
  ),
  profiles_lookup AS (
    SELECT user_id, display_name, avatar_url
    FROM profiles
    WHERE user_id IN (SELECT uid FROM all_user_ids)
  ),
  participants_lookup AS (
    SELECT pp.plan_id, pp.friend_id, pp.status, pp.role
    FROM plan_participants pp
    WHERE pp.plan_id IN (SELECT id FROM ordered_plans)
  )
  SELECT json_build_object(
    'plans', COALESCE((SELECT json_agg(row_to_json(op)) FROM ordered_plans op), '[]'::json),
    'participants', COALESCE((SELECT json_agg(row_to_json(pl)) FROM participants_lookup pl), '[]'::json),
    'profiles', COALESCE((SELECT json_agg(row_to_json(pr)) FROM profiles_lookup pr), '[]'::json)
  ) INTO result;

  RETURN result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_plan_invite_details(p_token text)
 RETURNS TABLE(invite_id uuid, plan_id uuid, plan_title text, plan_activity text, plan_date timestamp with time zone, plan_time_slot text, plan_duration integer, plan_location text, plan_notes text, plan_start_time time without time zone, plan_end_time time without time zone, invited_by_name text, invited_by_avatar text, invite_status text, invite_email text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    pi.id AS invite_id,
    p.id AS plan_id,
    p.title AS plan_title,
    p.activity AS plan_activity,
    p.date AS plan_date,
    p.time_slot AS plan_time_slot,
    p.duration AS plan_duration,
    p.location AS plan_location,
    p.notes AS plan_notes,
    p.start_time AS plan_start_time,
    p.end_time AS plan_end_time,
    pr.display_name AS invited_by_name,
    pr.avatar_url AS invited_by_avatar,
    pi.status AS invite_status,
    pi.email AS invite_email
  FROM plan_invites pi
  JOIN plans p ON p.id = pi.plan_id
  JOIN profiles pr ON pr.user_id = pi.invited_by
  WHERE pi.invite_token = p_token
  LIMIT 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_plans_by_share_code(p_share_code text, p_start_date timestamp with time zone, p_end_date timestamp with time zone)
 RETURNS TABLE(id uuid, title text, activity text, date timestamp with time zone, time_slot text, duration integer, location text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT 
    pl.id,
    pl.title,
    pl.activity,
    pl.date,
    pl.time_slot,
    pl.duration,
    pl.location
  FROM public.plans pl
  JOIN public.profiles p ON p.user_id = pl.user_id
  WHERE p.share_code = p_share_code
    AND p.show_availability = true
    AND pl.date >= p_start_date
    AND pl.date <= p_end_date
  ORDER BY pl.date;
$function$
;

CREATE OR REPLACE FUNCTION public.get_profile_by_share_code(p_share_code text)
 RETURNS TABLE(user_id uuid, display_name text, avatar_url text, current_vibe text, custom_vibe_tags text[], location_status text, show_availability boolean, show_vibe_status boolean, show_location boolean, allow_all_hang_requests boolean, allowed_hang_request_friend_ids uuid[], default_work_days text[], default_work_start_hour numeric, default_work_end_hour numeric, default_availability_status text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT 
    p.user_id,
    p.display_name,
    p.avatar_url,
    p.current_vibe,
    p.custom_vibe_tags,
    p.location_status,
    p.show_availability,
    p.show_vibe_status,
    p.show_location,
    p.allow_all_hang_requests,
    p.allowed_hang_request_friend_ids,
    p.default_work_days,
    p.default_work_start_hour,
    p.default_work_end_hour,
    p.default_availability_status
  FROM public.profiles p
  WHERE p.share_code = p_share_code
    AND p.show_availability = true
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.get_trip_invite_details(p_token text)
 RETURNS json
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invite RECORD;
  v_proposal RECORD;
  v_host RECORD;
  v_dates JSON;
  v_participant_count INT;
BEGIN
  SELECT * INTO v_invite
  FROM trip_proposal_invites
  WHERE invite_token = p_token
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN json_build_object('error', 'not_found');
  END IF;

  SELECT tp.id, tp.destination, tp.proposal_type, tp.status, tp.host_user_id, tp.created_by
  INTO v_proposal
  FROM trip_proposals tp
  WHERE tp.id = v_invite.proposal_id;

  IF NOT FOUND THEN
    RETURN json_build_object('error', 'proposal_not_found');
  END IF;

  SELECT p.user_id, p.display_name, p.first_name, p.last_name, p.avatar_url
  INTO v_host
  FROM profiles p
  WHERE p.user_id = COALESCE(v_proposal.host_user_id, v_proposal.created_by);

  SELECT COALESCE(json_agg(json_build_object(
    'id', d.id,
    'start_date', d.start_date,
    'end_date', d.end_date,
    'votes', d.votes
  ) ORDER BY d.start_date), '[]'::json)
  INTO v_dates
  FROM trip_proposal_dates d
  WHERE d.proposal_id = v_proposal.id;

  SELECT COUNT(*) INTO v_participant_count
  FROM trip_proposal_participants
  WHERE proposal_id = v_proposal.id;

  RETURN json_build_object(
    'invite_status', v_invite.status,
    'proposal_id', v_proposal.id,
    'trip_id', v_invite.trip_id,
    'destination', v_proposal.destination,
    'proposal_type', v_proposal.proposal_type,
    'proposal_status', v_proposal.status,
    'host', json_build_object(
      'user_id', v_host.user_id,
      'display_name', v_host.display_name,
      'first_name', v_host.first_name,
      'last_name', v_host.last_name,
      'avatar_url', v_host.avatar_url
    ),
    'dates', v_dates,
    'participant_count', v_participant_count
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_vibe_recipient_names(p_vibe_send_id uuid)
 RETURNS TABLE(user_id uuid, display_name text)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only allow if the caller is the sender or a recipient of this vibe
  IF NOT (
    EXISTS (SELECT 1 FROM vibe_sends WHERE id = p_vibe_send_id AND sender_id = auth.uid())
    OR EXISTS (SELECT 1 FROM vibe_send_recipients WHERE vibe_send_id = p_vibe_send_id AND recipient_id = auth.uid())
  ) THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT vsr.recipient_id AS user_id, p.display_name
  FROM vibe_send_recipients vsr
  JOIN profiles p ON p.user_id = vsr.recipient_id
  WHERE vsr.vibe_send_id = p_vibe_send_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.profiles (user_id, display_name)
  VALUES (NEW.id, NULLIF(trim(NEW.raw_user_meta_data->>'display_name'), ''));
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_trip_proposal_participant(p_proposal_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.trip_proposal_participants
    WHERE proposal_id = p_proposal_id
    AND user_id = auth.uid()
  );
$function$
;

CREATE OR REPLACE FUNCTION public.link_invited_friends_on_signup()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  r RECORD;
  v_new_user_name TEXT;
BEGIN
  -- Get the new user's display name
  v_new_user_name := COALESCE(NEW.raw_user_meta_data->>'display_name', NEW.email);

  -- Find all friendship records where someone invited this email
  FOR r IN
    SELECT id, user_id, friend_name
    FROM public.friendships
    WHERE friend_email = NEW.email
      AND status = 'invited'
      AND friend_user_id IS NULL
  LOOP
    -- Update the existing invitation to connected
    UPDATE public.friendships
    SET friend_user_id = NEW.id,
        status = 'connected',
        updated_at = now()
    WHERE id = r.id;

    -- Create the reciprocal friendship (new user -> inviter)
    INSERT INTO public.friendships (user_id, friend_user_id, friend_name, friend_email, status)
    SELECT NEW.id, r.user_id, p.display_name, NULL, 'connected'
    FROM public.profiles p
    WHERE p.user_id = r.user_id
    ON CONFLICT DO NOTHING;
  END LOOP;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.link_plan_invites_on_signup()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  r RECORD;
  v_user_name TEXT;
BEGIN
  -- Find pending plan invites for this email
  FOR r IN
    SELECT pi.id, pi.plan_id, pi.invited_by
    FROM plan_invites pi
    WHERE pi.email = NEW.email AND pi.status = 'pending'
  LOOP
    -- Add as participant with 'invited' status (pending RSVP)
    INSERT INTO plan_participants (plan_id, friend_id, status, role)
    VALUES (r.plan_id, NEW.id, 'invited', 'participant')
    ON CONFLICT DO NOTHING;

    -- Mark invite as linked (not yet accepted by user)
    UPDATE plan_invites
    SET status = 'linked', accepted_by = NEW.id
    WHERE id = r.id;

    -- Auto-create friendships
    v_user_name := COALESCE(NEW.raw_user_meta_data->>'display_name', NEW.email);

    INSERT INTO friendships (user_id, friend_user_id, friend_name, status)
    VALUES (r.invited_by, NEW.id, v_user_name, 'connected')
    ON CONFLICT DO NOTHING;

    INSERT INTO friendships (user_id, friend_user_id, friend_name, status)
    SELECT NEW.id, r.invited_by, COALESCE(pr.display_name, 'Friend'), 'connected'
    FROM profiles pr WHERE pr.user_id = r.invited_by
    ON CONFLICT DO NOTHING;
  END LOOP;

  RETURN NEW;
END;
$function$
;

