 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.backfill_availability_for_user(NEW.user_id, 183);
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.set_push_tokens_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_availability_location_to_profile()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only sync if the availability date is today
  IF NEW.date = CURRENT_DATE THEN
    UPDATE public.profiles
    SET 
      location_status = COALESCE(NEW.location_status, 'home'),
      updated_at = now()
    WHERE user_id = NEW.user_id;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_friend_name_on_profile_update()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.display_name IS DISTINCT FROM OLD.display_name AND NEW.display_name IS NOT NULL THEN
    UPDATE public.friendships
    SET friend_name = NEW.display_name, updated_at = now()
    WHERE friend_user_id = NEW.user_id
      AND friend_name IS DISTINCT FROM NEW.display_name;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_calendar_access_token(p_user_id uuid, p_provider text, p_access_token text, p_expires_at timestamp with time zone)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.calendar_connections
     SET access_token_plain = p_access_token,
         expires_at         = p_expires_at,
         updated_at         = now()
   WHERE user_id = p_user_id AND provider = p_provider;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_conversation_on_message()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.conversations SET updated_at = now() WHERE id = NEW.conversation_id;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.upsert_calendar_connection(p_user_id uuid, p_provider text, p_access_token text, p_refresh_token text, p_expires_at timestamp with time zone, p_grant_id text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.calendar_connections (
    user_id, provider, access_token_plain, refresh_token_plain, expires_at, grant_id
  ) VALUES (
    p_user_id, p_provider, p_access_token, p_refresh_token, p_expires_at, p_grant_id
  )
  ON CONFLICT (user_id, provider) DO UPDATE
    SET access_token_plain  = EXCLUDED.access_token_plain,
        refresh_token_plain = EXCLUDED.refresh_token_plain,
        expires_at          = EXCLUDED.expires_at,
        grant_id            = EXCLUDED.grant_id,
        updated_at          = now();
END;
$function$
;

