 RETURNS SETOF uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT conversation_id FROM public.conversation_participants WHERE user_id = p_user_id;
$function$
;

CREATE OR REPLACE FUNCTION public.user_participated_plan_ids(p_user_id uuid)
 RETURNS SETOF uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT plan_id FROM public.plan_participants WHERE friend_id = p_user_id;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_open_invite_anchor()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.plan_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.plans WHERE id = NEW.plan_id AND user_id = NEW.user_id
    ) THEN
      RAISE EXCEPTION 'plan_id must reference a plan owned by the invite creator';
    END IF;
  END IF;
  IF NEW.trip_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.trips WHERE id = NEW.trip_id AND user_id = NEW.user_id
    ) THEN
      RAISE EXCEPTION 'trip_id must reference a trip owned by the invite creator';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ============================================================
-- Triggers
CREATE TRIGGER sync_availability_location_to_profile_trigger AFTER INSERT OR UPDATE OF location_status ON availability FOR EACH ROW EXECUTE FUNCTION sync_availability_location_to_profile();
CREATE TRIGGER trg_auto_create_trip_from_availability AFTER INSERT OR UPDATE ON availability FOR EACH ROW EXECUTE FUNCTION auto_create_trip_from_availability();
CREATE TRIGGER update_availability_updated_at BEFORE UPDATE ON availability FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_calendar_connections_updated_at BEFORE UPDATE ON calendar_connections FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_conversation_timestamp AFTER INSERT ON chat_messages FOR EACH ROW EXECUTE FUNCTION update_conversation_on_message();
CREATE TRIGGER update_friendships_updated_at BEFORE UPDATE ON friendships FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER on_hang_request_accepted AFTER UPDATE ON hang_requests FOR EACH ROW EXECUTE FUNCTION create_plans_on_hang_accepted();
CREATE TRIGGER update_hang_requests_updated_at BEFORE UPDATE ON hang_requests FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER on_open_invite_claim AFTER INSERT ON open_invite_responses FOR EACH ROW EXECUTE FUNCTION convert_open_invite_to_plan();
CREATE TRIGGER update_open_invite_responses_updated_at BEFORE UPDATE ON open_invite_responses FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_open_invites_updated_at BEFORE UPDATE ON open_invites FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER validate_open_invite_anchor_trigger BEFORE INSERT OR UPDATE ON open_invites FOR EACH ROW EXECUTE FUNCTION validate_open_invite_anchor();
CREATE TRIGGER on_plan_change_response AFTER UPDATE ON plan_change_responses FOR EACH ROW EXECUTE FUNCTION check_and_apply_plan_change();
CREATE TRIGGER trg_notify_plan_invite AFTER INSERT ON plan_participants FOR EACH ROW EXECUTE FUNCTION notify_plan_invite();
CREATE TRIGGER update_plans_updated_at BEFORE UPDATE ON plans FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_pods_updated_at BEFORE UPDATE ON pods FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER sync_friend_name_on_profile_update AFTER UPDATE ON profiles FOR EACH ROW EXECUTE FUNCTION sync_friend_name_on_profile_update();
CREATE TRIGGER trg_seed_availability_on_profile_create AFTER INSERT ON profiles FOR EACH ROW EXECUTE FUNCTION seed_availability_on_profile_create();
CREATE TRIGGER update_profiles_updated_at BEFORE UPDATE ON profiles FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
