CREATE POLICY "Authenticated friends can view availability" ON public.availability FOR SELECT TO authenticated USING (((auth.uid() = user_id) OR (EXISTS ( SELECT 1
   FROM friendships
  WHERE ((friendships.user_id = auth.uid()) AND (friendships.friend_user_id = availability.user_id) AND (friendships.status = 'connected'::text))))));
