CREATE POLICY "Recipients can view open invites targeted at them" ON public.open_invites FOR SELECT TO authenticated USING (((status = 'open'::text) AND (expires_at > now()) AND (((audience_type = 'all_friends'::text) AND (EXISTS ( SELECT 1
   FROM friendships
  WHERE ((friendships.user_id = open_invites.user_id) AND (friendships.friend_user_id = auth.uid()) AND (friendships.status = 'connected'::text))))) OR ((audience_type = 'pod'::text) AND (EXISTS ( SELECT 1
   FROM (pod_members pm
     JOIN pods p ON ((p.id = pm.pod_id)))
  WHERE ((p.user_id = open_invites.user_id) AND (('pod:'::text || (pm.pod_id)::text) = ('pod:'::text || open_invites.audience_ref)) AND (pm.friend_user_id = auth.uid()))))) OR ((audience_type = 'interest'::text) AND (EXISTS ( SELECT 1
   FROM (friendships f
     JOIN profiles pr ON ((pr.user_id = auth.uid())))
  WHERE ((f.user_id = open_invites.user_id) AND (f.friend_user_id = auth.uid()) AND (f.status = 'connected'::text) AND (open_invites.audience_ref = ANY (pr.interests)))))) OR ((audience_type = 'friends'::text) AND (audience_ref IS NOT NULL) AND ((auth.uid())::text = ANY (string_to_array(audience_ref, ','::text))) AND (EXISTS ( SELECT 1
   FROM friendships
  WHERE ((friendships.user_id = open_invites.user_id) AND (friendships.friend_user_id = auth.uid()) AND (friendships.status = 'connected'::text))))))));
CREATE POLICY "Users can create their own open invites" ON public.open_invites FOR INSERT TO authenticated WITH CHECK ((auth.uid() = user_id));
