CREATE POLICY "Authenticated users can view friend profiles" ON public.profiles FOR SELECT TO authenticated USING (((auth.uid() = user_id) OR (EXISTS ( SELECT 1
   FROM friendships
  WHERE ((friendships.user_id = auth.uid()) AND (friendships.friend_user_id = profiles.user_id) AND (friendships.status = 'connected'::text))))));
CREATE POLICY "Users can delete their own profile" ON public.profiles FOR DELETE TO public USING ((auth.uid() = user_id));
CREATE POLICY "Users can insert their own profile" ON public.profiles FOR INSERT TO public WITH CHECK ((( SELECT auth.uid() AS uid) = user_id));
CREATE POLICY "Users can update their own profile" ON public.profiles FOR UPDATE TO public USING ((( SELECT auth.uid() AS uid) = user_id));
CREATE POLICY "Users can view their own profile" ON public.profiles FOR SELECT TO public USING ((( SELECT auth.uid() AS uid) = user_id));
