   FROM trip_activity_suggestions s
  WHERE ((s.id = trip_activity_votes.suggestion_id) AND is_trip_proposal_participant(s.proposal_id))))));
CREATE POLICY "Participants can view activity votes" ON public.trip_activity_votes FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM trip_activity_suggestions s
  WHERE ((s.id = trip_activity_votes.suggestion_id) AND is_trip_proposal_participant(s.proposal_id)))));
