CREATE POLICY "Connected friends can view trip participants" ON public.trip_participants FOR SELECT TO public USING ((EXISTS ( SELECT 1
   FROM (trips t
     JOIN friendships f ON (((f.user_id = auth.uid()) AND (f.friend_user_id = t.user_id) AND (f.status = 'connected'::text))))
  WHERE (t.id = trip_participants.trip_id))));
CREATE POLICY "Participants can view their own participation" ON public.trip_participants FOR SELECT TO public USING ((auth.uid() = friend_user_id));
CREATE POLICY "Trip owners can manage participants" ON public.trip_participants FOR ALL TO public USING ((EXISTS ( SELECT 1
   FROM trips
  WHERE ((trips.id = trip_participants.trip_id) AND (trips.user_id = auth.uid()))))) WITH CHECK ((EXISTS ( SELECT 1
   FROM trips
  WHERE ((trips.id = trip_participants.trip_id) AND (trips.user_id = auth.uid())))));
CREATE POLICY "Creator can manage proposal dates" ON public.trip_proposal_dates FOR ALL TO public USING ((EXISTS ( SELECT 1
   FROM trip_proposals tp
  WHERE ((tp.id = trip_proposal_dates.proposal_id) AND (tp.created_by = auth.uid()))))) WITH CHECK ((EXISTS ( SELECT 1
