  WHERE ((tp.id = trip_proposal_dates.proposal_id) AND (tp.created_by = auth.uid())))));
CREATE POLICY "Participants can view proposal dates" ON public.trip_proposal_dates FOR SELECT TO public USING ((EXISTS ( SELECT 1
   FROM trip_proposal_participants tpp
  WHERE ((tpp.proposal_id = trip_proposal_dates.proposal_id) AND (tpp.user_id = auth.uid())))));
