CREATE POLICY "Participants can view co-participants" ON public.trip_proposal_participants FOR SELECT TO authenticated USING (is_trip_proposal_participant(proposal_id));
CREATE POLICY "Participants can view trip votes" ON public.trip_proposal_votes FOR SELECT TO public USING ((EXISTS ( SELECT 1
   FROM (trip_proposal_dates tpd
     JOIN trip_proposal_participants tpp ON ((tpp.proposal_id = tpd.proposal_id)))
  WHERE ((tpd.id = trip_proposal_votes.date_id) AND (tpp.user_id = auth.uid())))));
