  WHERE ((tpd.id = trip_proposal_votes.date_id) AND (tpp.user_id = auth.uid()))))));
CREATE POLICY "Users can update their trip votes" ON public.trip_proposal_votes FOR UPDATE TO public USING ((auth.uid() = user_id)) WITH CHECK ((auth.uid() = user_id));
